import UIKit
import LocalAuthentication

class LoginViewController: UIViewController {

    @IBOutlet weak var usernameField: UITextField!
    @IBOutlet weak var passwordField: UITextField!
    @IBOutlet weak var loginButton: UIButton!

    var isUserAuthenticated = false

    override func viewDidLoad() {
        super.viewDidLoad()
        
        let defaults = UserDefaults.standard
        if (defaults.bool(forKey: "isUserAuthenticated")) {
            self.isUserAuthenticated = true
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            let mainVC = storyboard.instantiateViewController(withIdentifier: "HomeViewController")
            self.present(mainVC, animated: true, completion: nil)
        }
    }

    @IBAction func loginButtonPressed(_ sender: UIButton) {
        
        guard !self.isUserAuthenticated else { return }
        
        if LAContext().canEvaluatePolicy(.authAuthenticatorAllowExtendedAuthentication,
                                          error: nil) {
            
            let context = LAContext()
            context.evaluatePolicy(.authAuthenticatable, localizedReason: "Authenticate with Face ID") { [weak self] (success, error) in
                
                guard success else {
                    
                    if let error = error as? LAError {
                        switch error.code {
                        case .appCancel:
                            print("User cancelled authentication")
                            break
                        default:
                            print("Biometric auth failed: \(error.localizedDescription)")
                            DispatchQueue.main.async {
                                self?.showAlert("Biometric Auth Failed", message: "Try again or enter your password")
                            }
                        }
                    } else {
                        print("Biometric auth failed: \(String(describing: error))")
                        DispatchQueue.main.async {
                            self?.showAlert("Biometric Auth Failed", message: "Try again or enter your password")
                        }
                    }
                    return
                }
                
                let defaults = UserDefaults.standard
                defaults.set(true, forKey: "isUserAuthenticated")
                self!.dismiss(animated: true, completion: nil)
            }
        } else {
            // Fallback to password entry if Face ID/Touch ID is not available
            
            self.showAlert("Biometric Auth Not Available", message: "Enter your username and password to login.")
            
            guard let username = self.usernameField.text, !username.isEmpty else {
                self.showErrorAlert("Username cannot be empty")
                return
            }
            
            guard let password = self.passwordField.text, !password.isEmpty else {
                self.showErrorAlert("Password cannot be empty")
                return
            }
            
            if username == "your_username" && password == "your_password" {
                
                let defaults = UserDefaults.standard
                defaults.set(true, forKey: "isUserAuthenticated")
                self.dismiss(animated: true, completion: nil)
            } else {
                self.showErrorAlert("Incorrect Username or Password")
            }
        }
    }

    func showErrorAlert(_ message: String) {
        
        let alertController = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        let action = UIAlertAction(title: "Dismiss", style: .cancel, handler: nil)
        alertController.addAction(action)
        self.present(alertController, animated: true, completion: nil)
    }

    func showAlert(_ title: String, message: String) {
        
        let alertController = UIAlertController(title: title, message: message, preferredStyle: .alert)
        let tryAgainAction = UIAlertAction(title: "Try Again", style: .default, handler: { action in
            self.loginButtonPressed(self.loginButton)
        })
        
        let passwordAction = UIAlertAction(title: "Enter Password", style: .default) {
            [weak self] (action) in
            
            guard let username = self?.usernameField.text, !username.isEmpty else {
                self?.showErrorAlert("Username cannot be empty")
                return
            }
            
            guard let password = self?.passwordField.text, !password.isEmpty else {
                self?.showErrorAlert("Password cannot be empty")
                return
            }
            
            if username == "your_username" && password == "your_password" {
                
                let defaults = UserDefaults.standard
                defaults.set(true, forKey: "isUserAuthenticated")
                self!.dismiss(animated: true, completion: nil)
            } else {
                self?.showErrorAlert("Incorrect Username or Password")
            }
        }
        
        alertController.addAction(tryAgainAction)
        alertController.addAction(passwordAction)
        self.present(alertController, animated: true, completion: nil)
    }
}